    { name: "冰岛羊肉汤", cuisine: "冰岛", native: "Kjötsúpa", note: "羊肉配根茎菜的清炖汤，冰岛驱寒国民汤。", type: "汤", flavor: ["咸鲜"], spice: 0, diet: "荤", protein: ["羊"] }
