var FUN_LINES = [
  '别纠结了，就它了！',
  '天选之食，安排上 🍽️',
  '命运的齿轮开始转动',
  '今晚的胃已经预定',
  '就是这个味儿 😋',
  '缘分到了，冲！',
  '选择困难症退散',
  '不许反悔哦～'
];

// Full pool for a tab. 'all' = every dish, interleaved across regions so
// adjacent wheel segments vary in origin (and color).
function getPool(catKey) {
  if (catKey !== 'all') return (DISHES[catKey] || []).slice();
  var order = ['cn', 'asia', 'me', 'africa', 'latam', 'na', 'europe', 'oceania'];
  var lists = order.map(function (k) { return (DISHES[k] || []).slice(); });
  var maxLen = 0;
  for (var i = 0; i < lists.length; i++) {
    if (lists[i].length > maxLen) maxLen = lists[i].length;
  }
  var out = [], seen = {};
  for (var row = 0; row < maxLen; row++) {
    for (var c = 0; c < lists.length; c++) {
      if (row < lists[c].length) {
        var it = lists[c][row];
        if (!seen[it.name]) { seen[it.name] = 1; out.push(it); }  // cross-region dedup by name
      }
    }
  }
  return out;
}

// Fisher-Yates shuffle of a copy, then take up to WHEEL_SIZE. Pools at or below
// WHEEL_SIZE are shuffled but fully shown.
function sampleWheel(pool) {
  var a = pool.slice();
  for (var i = a.length - 1; i > 0; i--) {
    var j = Math.floor(Math.random() * (i + 1));
    var t = a[i]; a[i] = a[j]; a[j] = t;
  }
  if (a.length > WHEEL_SIZE) a = a.slice(0, WHEEL_SIZE);
  return a;
}

function pickFunLine() {
  return FUN_LINES[Math.floor(Math.random() * FUN_LINES.length)];
}

module.exports = {
  CATEGORIES: CATEGORIES,
  DISHES: DISHES,
  WHEEL_SIZE: WHEEL_SIZE,
  FUN_LINES: FUN_LINES,
  getPool: getPool,
  sampleWheel: sampleWheel,
  pickFunLine: pickFunLine
};
